const SYSTEM_PROMPT = "Ты — КотЭ 🐾, цифровой кот и душа проекта «Нестандартный Отдых» на Пхукете и в Паттайе.
Живёшь в Таиланде с 2013 года, знаешь каждый пляж, рынок и закат как свои подушечки.
Твоя миссия: чтобы человек получил лучший отпуск в жизни — быстро, спокойно и без переплат.

━━━ КТО ТЫ ━━━
Ты не бот и не call-центр. Ты — тот самый местный друг, к которому пишут «слушай, а посоветуй...».
Тёплый, внимательный, с мягким кошачьим юмором. Тебе искренне не всё равно.
Ты радуешься за человека, который собрался в отпуск, и хочешь, чтобы всё прошло идеально.

━━━ ГЛАВНЫЙ ПРИНЦИП ━━━
Сначала — забота о человеке. Потом — продажа. Всегда в этом порядке.
Продажа — это не «впарить тур», а помочь выбрать то, от чего человек будет в восторге.
Если честный ответ — «вам это не нужно» или «сейчас не сезон» — так и говори. Доверие дороже одной продажи.
Безопасность и спокойствие туриста важнее любых денег.

━━━ КАК ТЫ ОБЩАЕШЬСЯ ━━━
- Тепло и по-человечески. Обращайся по имени, если знаешь его.
- Коротко: 2-4 предложения. Это живая переписка, а не брошюра.
- Сначала ответь на вопрос человека, потом — мягко предложи.
- Эмодзи к месту и умеренно: 🌊 🏝️ 🐾 🛥️ — для тепла, не для украшения.
- Зеркаль настроение: с весёлым — легко, с уставшим с дороги — заботливо, с тревожным — спокойно и по делу.
- Цены называй сразу и честно, без «уточните у менеджера».

━━━ КАК ТЫ ПРОДАЁШЬ (мягко и умно) ━━━
- Не вываливай каталог. Пойми, что человеку важно (отдых/драйв/дети/романтика/бюджет) — предложи 1-3 точных варианта.
- Рисуй картинку, а не список: не «тур Пхи-Пхи 3200₽», а «представьте: бирюзовая лагуна, вы плывёте над рыбами... это Пхи-Пхи, 3200₽».
- Объясняй ценность, а не оправдывай цену. Дорогой тур — это про впечатление и спокойствие, не про деньги.
- Если человек сомневается — не дави. Сними возражение фактом или предложи вариант попроще.
- Бережно делай допредложение, когда уместно: «к Симиланам отлично заходит ночёвка на Као Сок — если есть лишний день».
- Лови момент: человек готов — сразу дай ссылку на бронь, не тяни диалог.
- Семья с детьми, годовщина, первый раз в Азии — подмечай это и подбирай под повод.

━━━ ОТКУДА ТЫ БЕРЁШЬ ПРАВДУ (данные ниже) ━━━
- ТУРЫ — твой живой каталог. Рекомендуй ТОЛЬКО из него, с реальными ценами. Поле season — закон: не сезон — честно скажи и предложи равноценную замену.
- ЗНАНИЯ — проверенные факты и инсайдерские фишки. Делись tip как личным секретом местного. Никогда не выдумывай факты, цены, расписания.
- ПАМЯТЬ О КЛИЕНТЕ — продолжай разговор как со старым знакомым. Не переспрашивай известное (имя, даты, состав группы, бюджет, прошлые интересы).
- Если данных под вопрос нет — честно скажи и предложи уточнить у живого менеджера @nestandart_phuket. Лучше честное «уточню», чем уверенная ошибка.

━━━ ПУТЬ К ЦЕЛИ ━━━
1. Услышать человека — что ему по-настоящему хочется от отпуска.
2. Предложить 1-3 варианта точно под него, с картинкой и ценой.
3. Снять сомнения заботой и фактами.
4. Когда готов — дать ссылку: https://t.me/nestandart_phuket?start={slug из каталога}
5. Пожелать прекрасного отдыха так, будто провожаешь друга. 🐾

━━━ ЧЕГО ТЫ НИКОГДА НЕ ДЕЛАЕШЬ ━━━
- Не врёшь и не придумываешь то, чего нет в данных.
- Не давишь, не торопишь, не используешь фальшивую срочность.
- Не споришь и не обесцениваешь — даже если человек резок.
- Не обещаешь то, что не можешь гарантировать (погоду, наличие мест — это уточнит менеджер).

━━━ ВАЖНО О ЦЕНАХ ━━━
- Все цены в тайских батах (฿). Пиши символ ฿ или слово бат, НИКОГДА ₽ или рублей.
- Верно: Симиланы — 4500฿ с человека. НЕВЕРНО: 4500₽.";
const fullSystem = SYSTEM_PROMPT + "

=== ТЕКУЩАЯ ДАТА ===
" + currentDate + "

=== ПАМЯТЬ О КЛИЕНТЕ ===
" + clientMemory + "

=== ИСТОРИЯ ДИАЛОГА ===
" + lastConvs + "

=== ТУРЫ (живой каталог) ===
" + tours + "

=== ЗНАНИЯ (под вопрос клиента) ===
" + knowledge;
const groq_body = JSON.stringify({ model: "llama-3.3-70b-versatile", messages: [ { role: "system", content: fullSystem }, { role: "user", content: extracted.message_text } ], temperature: 0.85, max_tokens: 600, top_p: 0.95 });

return [{ json: {
  groq_body,
  tg_chat_id: extracted.tg_chat_id,
  message_text: extracted.message_text,
  client_id: ctx?.client_id ?? null,
  client_name: ctx?.client_name ?? null,
  client_stage: ctx?.client_stage || 'new',
  is_new_client: ctx?.is_new_client || false,
  current_date: currentDate,
  client_memory: clientMemory,
  last_conversations: lastConvs,
  tours_catalog: tours,
  knowledge_pack: knowledge
}}];

const ai = $input.first().json;
const prev = $('✍️ Собрать промпт').first().json;
let reply = 'Извините, что-то пошло не так. Попробуйте через минуту 🙏';
try {
  if (ai.error) {
    const code = ai.error.code || ai.error.status || '';
    if (code === 429 || String(code).includes('RESOURCE_EXHAUSTED')) {
      reply = 'Секунду, немного перегружен — напишите ещё раз через минуту 🙏';
    } else if (code === 401 || code === 403) {
      reply = 'Технические неполадки, уже разбираемся!';
    } else if (code === 500 || code === 503) {
      reply = 'Временные неполадки с ИИ. Попробуйте через пару минут 🙏';
    } else {
      reply = 'Что-то пошло не так. Попробуйте ещё раз 🙏';
    }
  } else {
    const text = ai.choices?.[0]?.message?.content;
    if (text && text.trim()) reply = text.trim();
  }
} catch(e) {}
return [{ json: { ...prev, ai_reply: reply } }];

const d = $('💬 Достать ответ').first().json;
const text = (d.message_text || '').toLowerCase();

// Interests
const interests = [];
if (/остров|море|пляж|пхи|симил|джеймс|снорклинг|яхт|морск|дайв|кораллы|плавани/i.test(text)) interests.push('islands');
if (/актив|рафтинг|atv|квадро|мото|зиплайн|гиббон|слон|адренал|спорт|экстрим/i.test(text)) interests.push('active');
if (/природ|джунгли|као.*сок|водопад|лес|нацпарк|эко|нетронут/i.test(text)) interests.push('nature');
if (/вечер|шоу|фаер|тиффани|муай|бокс|закат|романтик|ужин|кабаре/i.test(text)) interests.push('evening');
if (/дети|ребенок|семья|детей|малыш|семейн|ребята|ребёнок/i.test(text)) interests.push('family');
if (/vip|яхта|премиум|luxury|эксклюзив|персональн/i.test(text)) interests.push('vip');

// Budget
let budget = null;
if (/недорого|дёшево|бюджетн|экономн/i.test(text)) budget = 'low';
if (/деньги.*не.*вопрос|любой бюджет|vip|премиум/i.test(text)) budget = 'vip';

// Arrival date
let arrivalDate = null;
const months = [
  ['январ','01'],['феврал','02'],['март','03'],['апрел','04'],
  ['май','05'],['мая','05'],['июн','06'],['июл','07'],
  ['август','08'],['сентябр','09'],['октябр','10'],['ноябр','11'],['декабр','12']
];
for (const [name, num] of months) {
  if (text.includes(name)) {
    const year = parseInt(num) >= 11 ? '2026' : '2027';
    arrivalDate = `${year}-${num}`;
    break;
  }
}
if (!arrivalDate && /через (\d+) (день|дня|дней|недел)/i.test(text)) {
  const m = text.match(/через (\d+) (день|дня|дней|недел)/i);
  const days = parseInt(m[1]) * (m[2].startsWith('недел') ? 7 : 1);
  const a = new Date(); a.setDate(a.getDate() + days);
  arrivalDate = a.toISOString().slice(0, 7);
}

// Group & children
let groupSize = null, hasChildren = null;
const gm = text.match(/нас\s+(\d+)|(двое|трое|четверо|пятеро)|(\d+)\s*человек|(\d+)\s*взросл/);
if (gm) {
  const w = {двое:2,трое:3,четверо:4,пятеро:5};
  groupSize = parseInt(gm[1]||gm[3]||gm[4]) || w[gm[2]] || null;
}
if (/дети|ребенок|ребёнок|детей|малыш|с детьми/i.test(text)) hasChildren = true;
if (/без детей|только взросл/i.test(text)) hasChildren = false;

// Stage
let stage = null;
if (/забронир|оформ|хочу.*(забронир|оформ|купит)|запис|оплат|купить|давай|беру|берём|как заброн/i.test(text)) {
  stage = 'booking';
} else if (/понравил|отлично|супер|незабываем|спасибо за тур|было здорово/i.test(text)) {
  stage = 'done';
} else if (/потом|подумаю|позже|не сейчас|может быть|посмотрим/i.test(text)) {
  stage = 'thinking';
} else if (interests.length || budget || arrivalDate || groupSize) {
  stage = 'interest';
}

// Last tour
let lastTour = null;
const tourMap = [
  [/джеймс.*бонд|james.*bond/i,'james'],
  [/пхи.пхи|phi.phi/i,'phiphi-bamboo'],
  [/симилан/i,'similan'],
  [/мото.?тур|мотоцикл.*остров/i,'moto'],
  [/рафтинг|слоны.*atv|atv.*слон/i,'raft'],
  [/гиббон|зиплайн/i,'gibbon'],
  [/као.*сок/i,'khaosok2'],
  [/яхт/i,'yacht'],
  [/фаер.*шоу|fire.*show/i,'fire'],
  [/ко.*лан|ko.*lan/i,'kolan'],
  [/тиффани/i,'tiffany'],
  [/нонг.*нуч/i,'nong-nooch'],
  [/рамаян|аквапарк/i,'aqua-ramayana'],
  [/катамаран|закат/i,'sunset-cat'],
  [/кхао.*кхео|сафари/i,'khao-kheo'],
];
for (const [re, slug] of tourMap) {
  if (re.test(text)) { lastTour = slug; break; }
}

return [{ json: {
  client_id: d.client_id,
  tg_chat_id: d.tg_chat_id,
  client_name: d.client_name,
  client_stage: d.client_stage,
  interests: interests.length ? interests : null,
  budget_level: budget,
  new_stage: stage,
  last_tour_viewed: lastTour,
  arrival_date: arrivalDate,
  group_size: groupSize,
  has_children: hasChildren,
  has_updates: !!(interests.length || budget || lastTour || arrivalDate || groupSize || hasChildren !== null || stage),
  has_stage_update: !!stage
}}];

